const meta = $('7-D. Code - 날짜 파싱 + 후보 병합').first().json;
const raw = $json.text || $json.output || $json.response || $json.result || JSON.stringify($json);

function repairJsonText(input) {
  let s = String(input || '')
    .replace(/^\uFEFF/, '')
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first >= 0 && last >= first) s = s.slice(first, last + 1);
  s = s
    .replace(/\bNone\b/g, 'null')
    .replace(/\bTrue\b/g, 'true')
    .replace(/\bFalse\b/g, 'false')
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/}\s*{/g, '},{')
    .replace(/]\s*\[/g, '],[')
    .replace(/}\s*"/g, '},"')
    .replace(/]\s*"/g, '],"')
    .replace(/"(\s+)"/g, '",$1"');
  let out = '';
  let inString = false;
  let escaped = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (inString) {
      if (escaped) { out += ch; escaped = false; continue; }
      if (ch === '\\') { out += ch; escaped = true; continue; }
      if (ch === '"') { inString = false; out += ch; continue; }
      if (ch === '\n') { out += '\\n'; continue; }
      if (ch === '\r') continue;
      if (ch === '\t') { out += '\\t'; continue; }
      out += ch;
    } else {
      if (ch === '"') inString = true;
      out += ch;
    }
  }
  return out;
}

function parseJson(str) {
  if (typeof str !== 'string') return str;
  const repaired = repairJsonText(str);
  try {
    return JSON.parse(repaired);
  } catch (e) {
    const secondPass = repaired
      .replace(/}\s*,?\s*(?={)/g, '},')
      .replace(/]\s*,?\s*(?="scores")/g, '],');
    return JSON.parse(secondPass);
  }
}

let ai = { scores: [] };
let aiEvaluationFailed = false;
try { ai = parseJson(raw); } catch(e) { ai = { scores: [] }; aiEvaluationFailed = true; }

const scoreMap = new Map();
for (const s of (ai.scores || [])) {
  if (s.url) scoreMap.set(String(s.url), s);
  if (s.no) scoreMap.set(String(s.no), s);
}

const finalMax = meta.final_max || 20;
const list = (meta.candidates || []).map((item, idx) => {
  const s = scoreMap.get(item.url) || scoreMap.get(String(idx+1)) || {};
  const aiRel = Number(s.ai_relevance_score ?? 60);
  const companyFit = Number(s.company_fit_score ?? 60);
  const aiUse = Number(s.ai_usefulness_score ?? 60);
  const aiScore = Math.max(0, Math.min(100, (aiRel*0.35 + companyFit*0.35 + aiUse*0.30))) / 100;
  const finalScore = Math.min(1, item.heuristic_score*0.45 + aiScore*0.55);
  let label = s.recommendation_label;
  if (!label) {
    if (finalScore >= 0.85) label = '강력추천';
    else if (finalScore >= 0.70) label = '추천';
    else if (finalScore >= 0.55) label = '검토필요';
    else label = '제외권장';
  }
  return {
    rank: 0,
    title: item.title,
    url: item.url,
    summary: item.summary,
    content: item.summary,
    published_date: item.published_date,
    source: item.source,
    sources: item.sources || [item.source],
    score: Math.round(finalScore*1000)/1000,
    heuristic_score: item.heuristic_score,
    ai_relevance_score: aiRel,
    company_fit_score: companyFit,
    ai_usefulness_score: aiUse,
    recommendation_label: label,
    recommendation_reason: s.recommendation_reason || '',
    risk_note: s.risk_note || '',
    source_quality_score: item.source_quality_score,
    keyword_match_score: item.keyword_match_score,
    freshness_score: item.freshness_score,
    content_depth_score: item.content_depth_score,
    domain: item.domain,
    publisher: item.publisher || null,
    date_validation: item.date_validation
  };
}).filter(x => x.recommendation_label !== '제외권장')
  .sort((a,b) => b.score - a.score)
  .slice(0, finalMax)
  .map((x,i) => ({ ...x, rank: i+1 }));

return {
  success: true,
  ai_evaluation_status: aiEvaluationFailed ? 'FAILED_FALLBACK_TO_HEURISTIC' : 'OK',
  keyword: meta.keyword,
  search_intent: meta.search_intent,
  ko_queries: meta.ko_queries,
  en_queries: meta.en_queries,
  total: list.length,
  original_count: meta.original_count,
  candidate_count: meta.candidate_count,
  serper_count: meta.serper_count,
  naver_news_count: meta.naver_news_count,
  naver_web_count: meta.naver_web_count,
  naver_count: meta.naver_count,
  duplicate_count: meta.duplicate_count,
  date_filtered_count: meta.date_filtered_count,
  excluded_keyword_count: meta.excluded_keyword_count,
  searched_at: new Date().toISOString(),
  analysis_viewpoint: meta.analysis_viewpoint,
  report_type: meta.report_type,
  audience_level: meta.audience_level,
  report_depth: meta.report_depth,
  action_orientation: meta.action_orientation,
  risk_sensitivity: meta.risk_sensitivity,
  company_context_doc_id: meta.company_context_doc_id || '',
  extracted_date_range: meta.extracted_date_range || null,
  effective_start_date: meta.effective_start_date || meta.start_date || null,
  effective_end_date:   meta.effective_end_date   || meta.end_date   || null,
  company_context_loaded: meta.company_context_loaded || false,
  company_context_chars: meta.company_context_chars || 0,
  list
};

// 7-A에서 URL 패턴 날짜 검증 완료 → 그대로 전달
// scoring_prompt 재생성을 위해 candidates 기반으로 scoringInput 업데이트
const prev = $('7-A. Code - 날짜 미상 기사 분리').first().json;
const candidates = prev.candidates || [];

// candidate_rank 재부여
const reranked = candidates
  .sort((a, b) => b.heuristic_score - a.heuristic_score)
  .map((x, i) => ({ ...x, candidate_rank: i + 1 }));

return {
  ...prev,
  candidates: reranked,
  candidate_count: reranked.length
};

// 날짜 미상 기사에 URL 패턴으로 날짜 추출 시도
// HTTP 접속 없이 URL에서 날짜를 파싱해서 바로 검증
const prev = $input.first().json;
const candidates = prev.candidates || [];

function extractDateFromUrl(url) {
  const s = String(url || '');
  // 슬래시 구분 패턴: /2013/03/22/
  let m = s.match(/\/(20\d{2})\/([01]\d)\/([0-3]\d)\//);
  if (m) {
    const d = new Date(Number(m[1]), Number(m[2])-1, Number(m[3]));
    if (!isNaN(d.getTime())) return d.toISOString();
  }
  // 연속 8자리: 20260507
  m = s.match(/(20\d{2})([01]\d)([0-3]\d)/);
  if (m) {
    const y=Number(m[1]), mo=Number(m[2]), d2=Number(m[3]);
    if (mo>=1&&mo<=12&&d2>=1&&d2<=31) {
      const d = new Date(y, mo-1, d2);
      if (!isNaN(d.getTime())) return d.toISOString();
    }
  }
  // 구분자 패턴: 2013-03-22
  m = s.match(/(20\d{2})[-_.](0[1-9]|1[0-2])[-_.](0[1-9]|[12]\d|3[01])/);
  if (m) {
    const d = new Date(Number(m[1]), Number(m[2])-1, Number(m[3]));
    if (!isNaN(d.getTime())) return d.toISOString();
  }
  return null;
}

// 날짜 범위 필터
const filterStart = prev.start_date ? new Date(prev.start_date) : null;
const filterEnd   = prev.end_date   ? new Date(prev.end_date + 'T23:59:59') : null;

function isInRange(dateStr) {
  const hasDateFilter = !!(filterStart || filterEnd);
  if (!dateStr) {
    // 기간 필터 설정 시 날짜 미상 제외
    return !hasDateFilter;
  }
  try {
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return !hasDateFilter;
    if (filterStart && d < filterStart) return false;
    if (filterEnd   && d > filterEnd)   return false;
    return true;
  } catch(e) { return !hasDateFilter; }
}

let urlDateFound = 0;
let urlDateFiltered = 0;

const verified = candidates.map(item => {
  // 이미 날짜 있으면 그대로
  if (item.published_date && item.date_validation !== 'unknown_date') return item;
  // URL에서 날짜 추출 시도
  const urlDate = extractDateFromUrl(item.url);
  if (urlDate) {
    urlDateFound++;
    return { ...item, published_date: urlDate, date_validation: 'verified_from_url' };
  }
  return item;
}).filter(item => {
  const inRange = isInRange(item.published_date);
  if (!inRange) urlDateFiltered++;
  return inRange;
});

return {
  ...prev,
  candidates: verified,
  candidate_count: verified.length,
  url_date_found: urlDateFound,
  url_date_filtered: urlDateFiltered
};

// =============================================
// 8-B. Google Docs 회사 맥락 병합 + AI 평가 프롬프트 재조립
// =============================================

const prev = $('7-D. Code - 날짜 파싱 + 후보 병합').first().json;

function extractTextFromGoogleDocsBody(body) {
  const chunks = [];
  const walk = (node) => {
    if (!node || typeof node !== 'object') return;
    if (node.textRun && typeof node.textRun.content === 'string') {
      chunks.push(node.textRun.content);
      return;
    }
    for (const key of Object.keys(node)) {
      const value = node[key];
      if (Array.isArray(value)) value.forEach(walk);
      else if (value && typeof value === 'object') walk(value);
    }
  };
  walk(body);
  return chunks.join('');
}

function pickText(obj) {
  if (typeof obj === 'string') return obj;
  if (!obj || typeof obj !== 'object') return '';
  if (typeof obj.content === 'string') return obj.content;
  if (typeof obj.text === 'string') return obj.text;
  if (typeof obj.data === 'string') return obj.data;
  if (typeof obj.body === 'string') return obj.body;
  if (obj.body && Array.isArray(obj.body.content)) return extractTextFromGoogleDocsBody(obj.body);
  if (Array.isArray(obj.content)) return extractTextFromGoogleDocsBody({ content: obj.content });
  return JSON.stringify(obj);
}

function cleanContext(text) {
  return String(text || '')
    .replace(/\r/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]+/g, ' ')
    .trim()
    .slice(0, 6000);
}

function looksLikeGoogleErrorOrHtml(text) {
  const s = String(text || '').slice(0, 2000);
  return (
    s.includes('window[\'ppConfig\']') ||
    s.includes('페이지를 찾을 수 없음') ||
    s.includes('현재 파일을 열 수 없습니다') ||
    s.includes('<!DOCTYPE html') ||
    s.includes('<html') ||
    s.includes('Bad request') ||
    s.includes('The resource you are requesting could not be found')
  );
}

const googleDocsNodeFailed = !!($json.error || $json.message?.includes?.('Bad request'));
let companyContextRaw = googleDocsNodeFailed ? '' : pickText($json);
if (looksLikeGoogleErrorOrHtml(companyContextRaw)) companyContextRaw = '';

const companyContext = cleanContext(companyContextRaw) || `[회사 업무 맥락]
- 회사 맥락 문서를 불러오지 못했습니다. 이 경우 검색 키워드와 분석 관점만 기준으로 평가합니다.
- Google Docs 문서를 사용하려면 Webhook body에 company_context_doc_id 또는 company_context_doc_url을 전달하세요.
- Google Docs 노드에는 반드시 접근 권한이 있는 Google OAuth2 credential을 연결하세요.
- 문서가 Google Docs 원본문서가 아니라 Drive에 업로드된 DOCX/PDF라면 Google Docs 노드가 실패할 수 있습니다.`;

const candidates = prev.candidates || [];
const scoringInput = candidates.map((x,i) => ({
  no: i+1,
  title: x.title,
  url: x.url,
  summary: x.summary,
  source: x.source,
  sources: x.sources,
  published_date: x.published_date,
  domain: x.domain,
  heuristic_score: x.heuristic_score,
  source_quality_score: x.source_quality_score,
  keyword_match_score: x.keyword_match_score,
  freshness_score: x.freshness_score,
  date_validation: x.date_validation
}));

const scoringPrompt = `너는 기업 보직자용 리서치 자료를 선별하는 분석가다.
아래 회사 업무 맥락과 검색 의도를 기준으로 후보 자료를 평가하라.

[회사 업무 맥락]
${companyContext}

[검색 기간]
${prev.start_date ? `${prev.start_date} ~ ${prev.end_date || '현재'}` : '기간 미설정'}
※ date_validation이 unknown_date인 기사는 이 기간 외 자료일 수 있음

[검색 의도]
${prev.search_intent || prev.keyword || ''}

[핵심 키워드]
${(prev.core_keywords || []).join(', ')}

[확장 키워드]
${(prev.expansion_keywords || []).join(', ')}

[제외 키워드]
${(prev.must_exclude || prev.exclude_keywords || []).join(', ')}

[분석 관점]
${prev.analysis_viewpoint}

[평가 기준]
- 키워드와 직접 관련 있는가
- 회사 업무 맥락, 고객사, 서비스 확장 가능성, 내부 운영 관점과 연결되는가
- 보직자용 리포트의 근거 자료로 쓸 수 있는가
- 단순 광고, 채용공고, 유학생/단순노무/고용허가제 중심 자료, 명백히 무관한 자료만 '제외권장'으로 분류하라
- 불확실하거나 간접적으로 관련 있으면 반드시 '검토필요'로 분류하라. '제외권장'은 명백히 무관한 경우에만 사용하라
- 키워드와 부분적으로 연결되는 자료도 '검토필요' 이상으로 분류하라
- 제목과 요약만 보고 판단하되, 판단이 어려우면 '검토필요'로 분류하라
- date_validation이 'unknown_date'인 기사는 날짜를 알 수 없어 기간 외 자료일 수 있다. 이런 기사는 ai_relevance_score에서 20점을 감점하고, 내용이 명확하지 않으면 '제외권장'으로 분류하라
- 반드시 JSON 객체만 출력하라

[점수 기준]
- ai_relevance_score: 검색 키워드/의도 관련도 0~100
- company_fit_score: 회사 업무 맥락 적합도 0~100
- ai_usefulness_score: 리포트 근거 자료로서 활용성 0~100

[후보 자료 JSON]
${JSON.stringify(scoringInput, null, 2)}

[출력 형식]
{
  "scores": [
    {
      "no": 1,
      "url": "후보 URL",
      "ai_relevance_score": 0,
      "company_fit_score": 0,
      "ai_usefulness_score": 0,
      "recommendation_label": "강력추천|추천|검토필요|제외권장",
      "recommendation_reason": "회사 업무 맥락과 연결한 짧은 추천/감점 사유",
      "risk_note": "주의점 또는 추가 확인 필요사항",
      "keep": true
    }
  ]
}`;

return {
  ...prev,
  company_context_doc_id: prev.company_context_doc_id,
  company_context_loaded: companyContextRaw ? true : false,
  company_context_chars: companyContext.length,
  company_context: companyContext,
  scoring_prompt: scoringPrompt
};

const meta = $('4. Code - 검색어 JSON 정리 + API Job 생성').first().json;
const allItems = $input.all();

let serperList = [], naverNewsList = [], naverWebList = [], answer = null;
for (const item of allItems) {
  if (item.json.source === 'serper') { serperList = item.json.list || []; answer = item.json.answer || null; }
  if (item.json.source === 'naver_news') naverNewsList = item.json.list || [];
  if (item.json.source === 'naver_web') naverWebList = item.json.list || [];
}

const originalCount = serperList.length + naverNewsList.length + naverWebList.length;
const all = [...serperList, ...naverNewsList, ...naverWebList].filter(x => x.url && x.title);

function normUrl(url) {
  try {
    const u = new URL(url);
    u.hash = '';
    ['utm_source','utm_medium','utm_campaign','utm_term','utm_content','fbclid','gclid'].forEach(k => u.searchParams.delete(k));
    return u.hostname.replace(/^www\./,'').toLowerCase() + u.pathname.replace(/\/$/,'').toLowerCase();
  } catch(e) {
    return String(url || '').replace(/^https?:\/\//,'').split('?')[0].replace(/\/$/,'').toLowerCase();
  }
}

function cleanText(s) { return String(s || '').toLowerCase().replace(/[^\uac00-\ud7a3a-z0-9\s]/g,' ').replace(/\s+/g,' ').trim(); }
function tokens(s) { return new Set(cleanText(s).split(/\s+/).filter(t => t.length >= 2)); }
function jaccard(a,b) {
  const A=tokens(a), B=tokens(b);
  if (!A.size || !B.size) return 0;
  let inter=0; for (const x of A) if (B.has(x)) inter++;
  return inter/(A.size+B.size-inter);
}
function parseDate(x) {
  if (!x) return null;
  const d = new Date(x);
  return isNaN(d.getTime()) ? null : d;
}
function dateFromUrl(url) {
  const s = String(url || '');
  // 슬래시 구분 패턴: /2013/03/22/
  let m = s.match(/\/(20\d{2})\/([01]\d)\/([0-3]\d)\//);
  if (m) {
    const d = new Date(Number(m[1]), Number(m[2])-1, Number(m[3]));
    if (!isNaN(d.getTime())) return d;
  }
  // 연속 8자리: 20260507 또는 20130322
  m = s.match(/(20\d{2})([01]\d)([0-3]\d)/);
  if (m) {
    const y=Number(m[1]), mo=Number(m[2]), d2=Number(m[3]);
    if (mo>=1&&mo<=12&&d2>=1&&d2<=31) {
      const d = new Date(y, mo-1, d2);
      if (!isNaN(d.getTime())) return d;
    }
  }
  // 구분자 패턴: 2013-03-22, 2013.03.22
  m = s.match(/(20\d{2})[-_.](0[1-9]|1[0-2])[-_.](0[1-9]|[12]\d|3[01])/);
  if (m) {
    const d = new Date(Number(m[1]), Number(m[2])-1, Number(m[3]));
    if (!isNaN(d.getTime())) return d;
  }
  return null;
}
function bestDate(item) { return parseDate(item.published_date) || dateFromUrl(item.url); }
function inRange(item) {
  const d = bestDate(item);
  const start = meta.start_date ? new Date(meta.start_date) : null;
  const end   = meta.end_date   ? new Date(meta.end_date)   : null;
  const hasDateFilter = !!(start || end);

  if (!d) {
    // 기간 필터가 설정된 경우 날짜 미상 기사 제외
    // 최신 기사일수록 날짜 확인 가능, 날짜 모르면 오래된 자료일 가능성 높음
    if (hasDateFilter) return { ok: false, reason: 'unknown_date_filtered', score: 0 };
    return { ok: true, reason: 'unknown_date', score: 0.55 };
  }
  if (start && d < start) return { ok: false, reason: 'before_start_date', score: 0.05 };
  if (end) {
    const e = new Date(end); e.setHours(23,59,59,999);
    if (d > e) return { ok: false, reason: 'after_end_date', score: 0.05 };
  }
  return { ok: true, reason: 'within_range', score: 1 };
}
function domainOf(url) {
  try { return new URL(url).hostname.replace(/^www\./,'').toLowerCase(); } catch(e) { return ''; }
}

// 도메인 → 언론사명 매핑 (Naver API는 언론사명을 별도로 주지 않아, URL 도메인으로 유추한다)
const PUBLISHER_MAP = {
  'yna.co.kr': '연합뉴스', 'yonhapnewstv.co.kr': '연합뉴스TV', 'newsis.com': '뉴시스', 'news1.kr': '뉴스1',
  'chosun.com': '조선일보', 'biz.chosun.com': '조선비즈', 'chosunbiz.com': '조선비즈',
