  tbs = map[base.time_range] || null;
}

// ── must_include 강제 삽입 (ko_queries만, en_queries는 영어 그대로) ──
const mustIncludeKw = base.must_include_from_keyword || [];
if (mustIncludeKw.length) {
  koQueries = koQueries.map(q => {
    const qClean = q.replace(/"/g, '');
    const missing = mustIncludeKw.filter(k => !qClean.includes(k));
    return missing.length ? `${missing.map(k => `"${k}"`).join(' ')} ${q}` : q;
  });
}

// ── Serper 쿼리 조합 (ko + en, 최대 8개) ──
const serperQueries = [
  ...koQueries.map(q => ({ q, hl:'ko', gl: base.gl || 'kr', language:'ko' })),
  ...enQueries.map(q => ({ q, hl:'en', gl:'us', language:'en' }))
].slice(0, 8);

// ── Naver 쿼리 (쌍따옴표 제거, must_include 키워드는 앞에 추가) ──
const naverMustKw = base.must_include_from_keyword || [];
const naverQueries = koQueries.slice(0, 5).map(q => {
  let naverQ = q.replace(/"/g, ''); // 쌍따옴표 제거
  // must_include 키워드가 쿼리에 없으면 앞에 추가 (쌍따옴표 없이)
  for (const k of naverMustKw) {
    if (!naverQ.includes(k)) naverQ = `${k} ${naverQ}`;
  }
  return { q: naverQ, language: 'ko' };
});

// ── Serper jobs 생성 ──
const SERPER_PAGES = 2;
const serper_jobs = [];
for (const q of serperQueries) {
  for (let page = 1; page <= SERPER_PAGES; page++) {
    serper_jobs.push({
      endpoint: base.topic === 'news'
        ? 'https://google.serper.dev/news'
        : 'https://google.serper.dev/search',
      q: q.q,
      hl: q.hl,
      gl: q.gl,
      num: 10,
      page,
      filter: 0,
      autocorrect: false,
      tbs,
      language: q.language
    });
  }
}

// ── Naver jobs 생성 ──
const naver_news_jobs = naverQueries.map(q => ({
  query: q.q,
  display: 30,
  sort: (base.start_date || base.end_date || base.time_range) ? 'date' : 'sim'
}));

const naver_web_jobs = naverQueries.slice(0, 3).map(q => ({
  query: q.q,
  display: 20
}));

return {
  ...base,
  search_intent:        parsed.search_intent || base.keyword,
  ko_queries:           koQueries,
  en_queries:           enQueries,
  must_include:         uniq(parsed.must_include || base.core_keywords),
  must_exclude:         uniq(parsed.must_exclude || base.exclude_keywords),
  serper_jobs,
  naver_news_jobs,
  naver_web_jobs,
  generated_query_raw:  parsed,
  extracted_date_range: extractedRange,
  effective_start_date: effectiveStartDate,
  effective_end_date:   effectiveEndDate
};

const data = $json.body || $json;
const tp = data.tavily_params || {};

// Google Docs에 저장한 회사/업무 맥락 문서
// company_context_doc_id 또는 company_context_doc_url 모두 허용
// company_context_doc_url 기본값 (미입력 시 기본 문서 사용)
const DEFAULT_COMPANY_CONTEXT_URL = 'https://docs.google.com/document/d/1FML9a8fOGfi4SsF19SWqWAEMpImaZRD1SjlLwp5ne00/edit?usp=drive_link';
const companyContextInput = String(
  data.company_context_doc_url ||
  data.company_context_google_doc_url ||
  data.company_context_doc_id ||
  data.company_context_google_doc_id ||
  tp.company_context_doc_url ||
  tp.company_context_doc_id ||
  ''
).trim();

function extractGoogleDocId(input) {
  const s = String(input || '').trim();
  if (!s) return '';
  const m = s.match(/\/document\/d\/([^\/]+)/);
  if (m) return m[1];
  return s;
}

const companyContextDocId = extractGoogleDocId(companyContextInput);
const companyContextDocUrl = companyContextDocId
  ? `https://docs.google.com/document/d/${companyContextDocId}/edit`
  : DEFAULT_COMPANY_CONTEXT_URL;

const splitList = (v) => {
  if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
  if (typeof v === 'string') return v.split(/[,，\n]+/).map(x => x.trim()).filter(Boolean);
  return [];
};

const rawKeyword = String(data.keyword || tp.query || '').trim();
const keyword = rawKeyword;

// 쌍따옴표로 감싼 단어 추출 → must_include (반드시 포함 키워드)
const quotedMatches = rawKeyword.match(/"([^"]+)"/g) || [];
const mustIncludeFromKeyword = quotedMatches.map(m => m.replace(/"/g, '').trim()).filter(Boolean);
const coreKeywords = splitList(data.core_keywords || data.main_keywords || keyword);
// 쌍따옴표 키워드를 coreKeywords 앞에 추가 (중복 제외)
for (const k of mustIncludeFromKeyword) {
  if (!coreKeywords.includes(k)) coreKeywords.unshift(k);
}
if (!coreKeywords.length && keyword) coreKeywords.push(keyword);

const expansionKeywords = splitList(data.expansion_keywords || data.sub_keywords || data.related_keywords || '');
const excludeKeywords = splitList(data.exclude_keywords || '');
const includeDomains = Array.isArray(tp.include_domains) ? tp.include_domains : splitList(data.include_domains || '');
const excludeDomains = Array.isArray(tp.exclude_domains) ? tp.exclude_domains : splitList(data.exclude_domains || '');

const topic = tp.topic || data.topic || 'news';
const timeRange = tp.time_range || data.time_range || null;

// days → start_date/end_date 자동 변환 (topic=news일 때)
let startDate = data.start_date || tp.start_date || null;
let endDate   = data.end_date   || tp.end_date   || null;

const days = tp.days ? Number(tp.days) : null;
if (days && !startDate && !endDate) {
  // days가 설정됐고 날짜 범위가 없으면 자동 계산
  const today = new Date();
  const from  = new Date();
  from.setDate(today.getDate() - days);
  startDate = from.toISOString().slice(0, 10);
  endDate   = today.toISOString().slice(0, 10);
}

const finalMax = Number(tp.max_results || data.max_results || 20);
const candidateMax = Number(data.candidate_max || 50);

const analysisViewpoint = data.analysis_viewpoint || 'business_expansion';
const reportType = data.report_type || 'trend_brief';
const audienceLevel = data.audience_level || 'division_head';
const reportDepth = data.report_depth || 'standard';
const actionOrientation = data.action_orientation !== undefined ? data.action_orientation : true;
const riskSensitivity = data.risk_sensitivity || 'normal';

const country = (tp.country || data.country || 'KR').toString();
const gl = country.slice(0,2).toLowerCase();

const todayStr = new Date().toISOString().slice(0, 10);

const queryPrompt = `너는 웹 리서치 검색어 설계 전문가다.
사용자의 키워드를 분석하여 검색어를 생성하고, 날짜 범위와 쌍따옴표 처리까지 판단하라.

[사용자 입력]
키워드: ${keyword}
핵심 키워드: ${coreKeywords.join(', ')}
확장 키워드: ${expansionKeywords.join(', ')}
제외 키워드: ${excludeKeywords.join(', ')}
분석 관점: ${analysisViewpoint}
리포트 유형: ${reportType}
사용자 설정 검색 기간: ${startDate || '미설정'} ~ ${endDate || '미설정'}
오늘 날짜: ${todayStr}

[쌍따옴표 처리 원칙]
- 사용자가 이미 쌍따옴표로 감싼 키워드는 반드시 그대로 유지
- 고유명사(기업명·기관명·인명·브랜드·법률명 등)는 쌍따옴표 추가
- 일반 키워드는 쌍따옴표 없이 그대로 사용
- 예) 삼성전자 → "삼성전자", 노란봉투법 → "노란봉투법", 동향 → 동향

[날짜 범위 추출 원칙]
- 사용자 키워드에서 시점 표현을 감지하여 날짜 범위를 계산하라
- "지난 N년" → start_date = 오늘로부터 N년 전, end_date = 오늘
- "지난 N개월" / "최근 N개월" → start_date = 오늘로부터 N개월 전, end_date = 오늘
- "최근" (단독) → start_date = 오늘로부터 3개월 전, end_date = 오늘
- "YYYY년" → start_date = YYYY-01-01, end_date = YYYY-12-31
- "YYYY" (4자리 연도) → 위와 동일
- 시점 표현 없으면 → start_date와 end_date 모두 null
- 사용자가 날짜를 이미 설정했으면 (미설정 아님) → 사용자 설정을 우선하고 extracted_date_range는 null로

[검색어 생성 원칙]
- ko_queries: 한국어 검색어 3~5개
- en_queries: 영어 검색어 3~5개
- 각 쿼리에 쌍따옴표 처리된 핵심 키워드를 반드시 포함
- 각 검색어는 120자 이하
- must_include 키워드는 ko_queries에만 포함시켜라. en_queries에는 영어 키워드만 사용하라
- exclude_keywords는 절대 쿼리에 넣지 말라. -키워드, NOT 연산자 형태도 금지. 후처리에서 처리한다
- 쿼리에는 찾고 싶은 긍정 키워드만 넣어라
- JSON 객체만 출력

[출력 형식]
{
  "search_intent": "검색 의도 한 문장",
  "ko_queries": ["한국어 검색어1", "한국어 검색어2"],
  "en_queries": ["english query 1", "english query 2"],
  "must_include": ["핵심 포함 개념 (쌍따옴표 포함 형태로)"],
  "must_exclude": ["제외 개념"],
  "extracted_date_range": {
    "start_date": "YYYY-MM-DD 또는 null",
    "end_date": "YYYY-MM-DD 또는 null",
    "reason": "날짜 추출 근거 한 문장"
  }
}`;

return {
  keyword,
  core_keywords: coreKeywords,
  expansion_keywords: expansionKeywords,
  exclude_keywords: excludeKeywords,
  include_domains: includeDomains,
  exclude_domains: excludeDomains,
  start_date: startDate,
  end_date: endDate,
